mapper.insert:

    SELECT seq_sbmsn_doc.nextval FROM dual              /*kr.or.ddit.domain.central.mapper.IContractUserMapper.insertContractDoc*/

INSERT INTO sbmsn_doc (
sbmsn_doc_no
, sbmsn_doc_ty_cd
, atch_file_id
, aplct_no
) VALUES (
#{sbmsnDocNo}
, #{sbmsnDocTyCd}
, #{atchFileId}
, #{aplctNo}
)

mapper.select:
SELECT ho_ty_no                 /*kr.or.ddit.domain.central.mapper.IContractUserMapper.selectHoTyNo*/
FROM apt_ho_ty
WHERE apt_cmplex_no = #{aptCmplexNo}
  AND ty_nm = #{tyNm}
  AND exclusive_size = #{exclusiveSize}
  AND ROWNUM = 1

SELECT count(*)             /*kr.or.ddit.domain.central.mapper.IContractUserMapper.selectAplctcount*/
FROM aplct
WHERE user_no = #{userNo}
AND ann_no = #{annNo}

mapper.update:
UPDATE center_ann_board_post                /*kr.or.ddit.domain.central.mapper.IContractUserMapper.updateInqCnt*/
SET inq_cnt = NVL(inq_cnt, 0) + 1
WHERE ann_no = #{annNo}

UPDATE aplct                    /*kr.or.ddit.domain.central.mapper.IContractUserMapper.cancelContract*/
SET aplct_stts_cd = 'CANCEL'
WHERE aplct_no = #{aplctNo}

mapper.delete:
DELETE
FROM sbmsn_doc
WHERE aplct_no = #{aplctNo}
AND sbmsn_doc_ty_cd = #{sbmsnDocTyCd}
